def remove_Occ(s: str, char: str) -> str:
    if len(char) != 1:
        raise ValueError("char must be a single character")

    first = s.find(char)
    last = s.rfind(char)

    if first == -1:
        return s

    if first == last:
        # Only one occurrence
        return s[:first] + s[first+1:]

    # Remove both first and last occurrences
    return s[:first] + s[first+1:last] + s[last+1:]

def text_lowercase_underscore(s: str) -> bool:
    if not s:
        return False

    # Check if the string contains only lowercase letters and underscores
    # and that underscores are only used as separators between lowercase letters
    if not all(c.islower() or c == '_' for c in s):
        return False

    # Ensure underscores are not at the start or end
    if s[0] == '_' or s[-1] == '_':
        return False

    # Ensure no two underscores are adjacent
    if '__' in s:
        return False

    # Ensure underscores are only between lowercase letters (already covered by the above checks,
    # but we can also verify that every '_' is surrounded by lowercase letters)
    for i, c in enumerate(s):
        if c == '_':
            if i == 0 or i == len(s) - 1:
                return False
            if not (s[i-1].islower() and s[i+1].islower()):
                return False

    return True

