def comb_sort(arr):
    if not arr:
        return arr

    n = len(arr)
    gap = n
    swapped = True

    while gap > 1 or swapped:
        # Calculate next gap using comb factor (1.3)
        gap = int(gap / 1.3)
        if gap < 1:
            gap = 1

        swapped = False
        for i in range(n - gap):
            if arr[i] > arr[i + gap]:
                arr[i], arr[i + gap] = arr[i + gap], arr[i]
                swapped = True

    return arr

