def is_samepatterns(patterns, pattern_map):
    """
    Check if the strings in 'patterns' follow the same substitution pattern as 'pattern_map'.

    Each character in 'pattern_map' maps to a unique string in 'patterns'.
    The function returns True if the mapping is consistent, False otherwise.

    Args:
        patterns (list of str): The list of strings to check.
        pattern_map (list of str): The list of pattern characters (e.g., "a", "b", "c").

    Returns:
        bool: True if the pattern mapping is consistent, False otherwise.
    """
    if len(patterns) != len(pattern_map):
        return False

    mapping = {}
    for p, char in zip(patterns, pattern_map):
        if char in mapping:
            if mapping[char] != p:
                return False
        else:
            mapping[char] = p

    # Ensure no two different characters map to the same string
    for char in mapping:
        if mapping[char] in mapping.values():
            continue
        # Check if any other character maps to the same value
        for other_char in mapping:
            if other_char != char and mapping[other_char] == mapping[char]:
                return False

    return True

def is_samepatterns(patterns, seq):
    """
    Check if the string sequence 'seq' follows the pattern defined in 'patterns'.

    Each character in 'patterns' maps to a corresponding character in 'seq'.
    The mapping must be consistent: the same character in 'patterns' must always
    map to the same character in 'seq', and different characters must map to different ones.

    Args:
        patterns (List[str]): A list of strings representing the pattern.
        seq (List[str]): A list of strings representing the sequence.

    Returns:
        bool: True if the sequence follows the pattern, False otherwise.
    """
    if len(patterns) != len(seq):
        return False

    pattern_to_char = {}
    char_to_pattern = {}

    for p, s in zip(patterns, seq):
        if p in pattern_to_char:
            if pattern_to_char[p] != s:
                return False
        else:
            if s in char_to_pattern:
                return False
            pattern_to_char[p] = s
            char_to_pattern[s] = p

    return True

