def is_undulating(n: int) -> bool:
    """
    Check if the given integer is an undulating number.
    An undulating number is a number whose adjacent digits are never equal,
    and the sequence of digits alternates between increasing and decreasing.
    Example: 1212121 -> True, 122121 -> False
    """
    s = str(n)
    if len(s) <= 2:
        return True  # By definition, single or double digit numbers are undulating

    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            return False
        if i == 1:
            direction = 1 if s[i] > s[i-1] else -1
        else:
            if direction == 1 and s[i] < s[i-1]:
                direction = -1
            elif direction == -1 and s[i] > s[i-1]:
                direction = 1
            else:
                return False
    return True

