    """
    Returns the number of divisors of the given positive integer n.

    Args:
        n (int): A positive integer.

    Returns:
        int: The count of divisors of n.
    """
    if n <= 0:
        raise ValueError("Input must be a positive integer.")

    count = 0
    i = 1
    while i * i <= n:
        if n % i == 0:
            if i * i == n:
                count += 1
            else:
                count += 2
        i += 1
    return count

