def search(arr):
    """
    Finds the element that appears only once in a sorted array.

    Args:
        arr (List[int]): A sorted list of integers where exactly one element appears once.

    Returns:
        int: The unique element.
    """
    n = len(arr)
    if n == 1:
        return arr[0]

    # Check if the unique element is at the beginning
    if arr[0] != arr[1]:
        return arr[0]

    # Check if the unique element is at the end
    if arr[-1] != arr[-2]:
        return arr[-1]

    # Binary search for the unique element
    left, right = 0, n - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, compare with next; if odd, compare with previous
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                right = mid
        else:
            if arr[mid] == arr[mid - 1]:
                left = mid
            else:
                right = mid - 1

    return arr[left]

def search(arr):
    """
    Finds the element that appears only once in a sorted array.

    Args:
        arr (List[int]): A sorted list of integers where exactly one element appears once.

    Returns:
        int: The unique element.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element by comparing with neighbors
        if mid == 0:
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                return arr[mid]
        elif mid == len(arr) - 1:
            if arr[mid] == arr[mid - 1]:
                right = mid - 1
            else:
                return arr[mid]
        else:
            # If the pair at mid is even, the unique element must be to the right
            if arr[mid] == arr[mid + 1]:
                left = mid + 1
            else:
                # If the pair at mid is odd, the unique element must be to the left (including mid)
                right = mid

    return arr[left]

