def amicable_numbers_sum(n):
    def get_divisor_sum(num):
        if num <= 1:
            return 0
        total = 1  # 1 is always a divisor for num > 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    amicable_pairs = set()
    for num in range(1, n + 1):
        d = get_divisor_sum(num)
        if d != num and d != 0 and num + d <= n:
            if get_divisor_sum(d) == num:
                amicable_pairs.add(min(num, d))
                amicable_pairs.add(max(num, d))

    return sum(amicable_pairs)

