def zero_count(arr):
    zeroes = 0
    non_zeroes = 0
    for num in arr:
        if num == 0:
            zeroes += 1
        else:
            non_zeroes += 1

    total = zeroes + non_zeroes
    if total == 0:
        return 0.0

    return zeroes / total

