def pancake_sort(arr):
    n = len(arr)
    # Create a copy to avoid modifying the original list
    arr = arr.copy()

    # Start from the end of the list and move backwards
    for i in range(n - 1, 0, -1):
        # Find the maximum element's index in arr[0..i]
        max_idx = 0
        for j in range(1, i + 1):
            if arr[j] > arr[max_idx]:
                max_idx = j

        # If the maximum element is not at the correct position (index i)
        if max_idx != i:
            # If the maximum element is not at the top (index 0), flip it to top
            if max_idx != 0:
                flip(arr, max_idx)

            # Now flip the entire subarray [0..i] to put the max element at position i
            flip(arr, i)

    return arr

def flip(arr, k):
    """Flip the first k+1 elements of the array (indices 0 to k)."""
    arr[:k+1] = arr[:k+1][::-1]

def pancake_sort(arr):
    n = len(arr)
    current_max = n - 1

    while current_max > 0:
        # Find the index of the maximum element in arr[0..current_max]
        max_idx = 0
        for i in range(1, current_max + 1):
            if arr[i] > arr[max_idx]:
                max_idx = i

        # If the maximum element is already at the correct position, skip
        if max_idx == current_max:
            current_max -= 1
            continue

        # Move the maximum element to the top (index 0)
        if max_idx != 0:
            arr = flip(arr, max_idx)

        # Move the maximum element to its correct position at current_max
        if max_idx != current_max:
            arr = flip(arr, current_max)

        current_max -= 1

    return arr

def flip(arr, k):
    """Flip the first k+1 elements of the list."""
    return arr[:k+1][::-1] + arr[k+1:]

