def sequence(n):
    if n <= 0:
        raise ValueError("n must be a positive integer")

    if n == 1 or n == 2:
        return 1

    # Initialize the sequence array
    seq = [0] * (n + 1)
    seq[1] = 1
    seq[2] = 1

    # Compute the sequence using the recurrence relation
    for i in range(3, n + 1):
        seq[i] = seq[seq[i-1]] + seq[i - seq[i-1]]

    return seq[n]

def sequence(n):
    if n <= 0:
        raise ValueError("n must be a positive integer")

    # Newman-Conway sequence: a(1) = 1, a(n) = a(a(n-1)) + a(n - a(n-1))
    a = [0] * (n + 1)
    a[1] = 1

    for i in range(2, n + 1):
        a[i] = a[a[i-1]] + a[i - a[i-1]]

    return a[n]

