def is_undulating(n):
    """
    Check whether the given number is undulating.
    An undulating number has digits that alternate between increasing and decreasing.
    """
    digits = [int(d) for d in str(n)]

    if len(digits) <= 2:
        return True

    direction = None  # None means no direction set yet

    for i in range(len(digits) - 1):
        current_diff = digits[i + 1] - digits[i]

        if current_diff > 0:
            # Increasing
            if direction is not None and direction != 1:
                return False
            direction = 1
        elif current_diff < 0:
            # Decreasing
            if direction is not None and direction != -1:
                return False
            direction = -1
        # current_diff == 0 is not allowed (same consecutive digits)

    return True

