def magic_square_test(matrix):
    """
    Check if a given matrix is a magic square.

    A magic square is a square grid of numbers where:
    - All rows, columns, and two main diagonals sum to the same value
    - All numbers are distinct positive integers from 1 to n^2
    """
    n = len(matrix)

    # Check if matrix is square
    if not all(len(row) == n for row in matrix):
        return False

    # Check if matrix is actually square (n x n)
    if n == 0:
        return False

    # Check if all elements are positive integers
    for row in matrix:
        for num in row:
            if not isinstance(num, int) or num <= 0:
                return False

    # Check if all numbers are unique and from 1 to n^2
    all_numbers = []
    for row in matrix:
        all_numbers.extend(row)

    if len(set(all_numbers)) != n * n:
        return False

    # Check if numbers are from 1 to n^2
    if set(all_numbers) != set(range(1, n * n + 1)):
        return False

    # Calculate the expected sum (sum of first row)
    expected_sum = sum(matrix[0])

    # Check all rows
    for row in matrix:
        if sum(row) != expected_sum:
            return False

    # Check all columns
    for col_idx in range(n):
        col_sum = sum(matrix[row_idx][col_idx] for row_idx in range(n))
        if col_sum != expected_sum:
            return False

    # Check main diagonal
    main_diag_sum = sum(matrix[i][i] for i in range(n))
    if main_diag_sum != expected_sum:
        return False

    # Check anti-diagonal
    anti_diag_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diag_sum != expected_sum:
        return False

    return True

