def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    vowels_list = list(s)
    left, right = 0, len(vowels_list) - 1

    while left < right:
        # Move left pointer to next vowel
        while left < right and vowels_list[left] not in vowels:
            left += 1
        # Move right pointer to previous vowel
        while left < right and vowels_list[right] not in vowels:
            right -= 1

        # Swap the vowels
        if left < right:
            vowels_list[left], vowels_list[right] = vowels_list[right], vowels_list[left]
            left += 1
            right -= 1

    return ''.join(vowels_list)

