def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 1:
        return 1 if m == 0 else 0

    dp = [[0] * n for _ in range(n)]
    dp[0][0] = 1

    for i in range(1, n):
        for j in range(i):
            dp[i][j] = (j + 1) * dp[i-1][j] + (i - j) * dp[i-1][j-1]

    return dp[n-1][m]

def eulerian_num(n, m):
    """
    Calculate the Eulerian number a(n, m).

    Eulerian numbers count the number of permutations of length n with exactly m ascents.

    Parameters:
        n (int): The length of the permutation (n >= 1)
        m (int): The number of ascents (0 <= m <= n-1)

    Returns:
        int: The Eulerian number a(n, m)
    """
    # Base case
    if n == 0:
        return 0
    if m < 0 or m >= n:
        return 0
    if n == 1:
        return 1 if m == 0 else 0

    # Use dynamic programming with memoization
    memo = {}

    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]

        if i == 1:
            memo[(i, j)] = 1 if j == 0 else 0
            return memo[(i, j)]

        # Recurrence: A(n, m) = (m+1) * A(n-1, m) + (n-m) * A(n-1, m-1)
        result = (j + 1) * dp(i - 1, j) + (i - j) * dp(i - 1, j - 1)
        memo[(i, j)] = result
        return result

    return dp(n, m)

