def find_solution(a, b, n):
    """
    Find integers x and y such that ax + by = n.

    Args:
        a: Coefficient for x
        b: Coefficient for y
        n: Target value

    Returns:
        Tuple (x, y) if solution exists, None otherwise
    """
    def extended_gcd(a, b):
        """Extended Euclidean Algorithm: returns (gcd, x, y) such that ax + by = gcd"""
        if a == 0:
            return b, 0, 1
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return gcd, x, y

    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    if a == 0:
        if n % b == 0:
            return (0, n // b)
        return None

    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        return None

    gcd, x0, y0 = extended_gcd(a, b)

    if n % gcd != 0:
        return None

    x = x0 * (n // gcd)
    y = y0 * (n // gcd)

    return (x, y)


