def eulerian_num(n, m):
    if n == 0:
        return 1 if m == 0 else 0

    if m < 0 or m > n - 1:
        return 0

    # Create a table for dynamic programming
    dp = [[0] * n for _ in range(n)]
    dp[0][0] = 1

    for i in range(1, n):
        for j in range(i):
            dp[i][j] = (j + 1) * dp[i-1][j] + (i - j) * dp[i-1][j-1]

    return dp[n-1][m]

def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0
    if n == 1:
        return 1

    memo = {}

    def helper(n, m):
        if (n, m) in memo:
            return memo[(n, m)]

        # Base case: for n=1, only m=0 is valid
        if n == 1:
            result = 1 if m == 0 else 0
        else:
            # Eulerian number recurrence relation
            result = (m + 1) * helper(n - 1, m) + (n - m) * helper(n - 1, m - 1)

        memo[(n, m)] = result
        return result

    return helper(n, m)

