    digits = [int(d) for d in str(n)]

    # Need at least 2 digits to have an undulating pattern
    if len(digits) < 2:
        return False

    # Check if consecutive digits alternate between increasing and decreasing
    for i in range(len(digits) - 1):
        # Equal consecutive digits are not allowed
        if digits[i] == digits[i+1]:
            return False

        # Check if the pattern alternates
        if i > 0:
