def is_undulating(n):
    # Convert to string to get digits
    s = str(n)

    # Need at least 2 digits
    if len(s) < 2:
        return False

    # Get all adjacent comparisons
    comparisons = []
    for i in range(len(s) - 1):
        if s[i] < s[i+1]:
            comparisons.append('<')
        elif s[i] > s[i+1]:
            comparisons.append('>')
        else:
            # Equal digits - not undulating
            return False

    # Check if comparisons alternate
    for i in range(len(comparisons) - 1):
        if comparisons[i] == comparisons[i+1]:
            return False

    return True

