def eulerian_num(n, m):
    if m < 0 or m >= n:
        return 0

    if n == 1:
        return 1 if m == 0 else 0

    # dp[i][j] represents A(i, j)
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    dp[1][0] = 1

    for i in range(2, n + 1):
        for j in range(i):
            dp[i][j] = (i - j) * dp[i-1][j-1] if j > 0 else 0
            dp[i][j] += (j + 1) * dp[i-1][j]

    return dp[n][m]

def eulerian_num(n, m):
    """
    Calculate the Eulerian number a(n, m).

    The Eulerian number A(n, m) is the number of permutations of {1, 2, ..., n}
    that have exactly m ascents.

    Args:
        n: Positive integer (number of elements in permutation)
        m: Non-negative integer (number of ascents)

    Returns:
        The Eulerian number A(n, m)
    """
    if m < 0 or m >= n:
        return 0

    if n == 1:
        return 1 if m == 0 else 0

    # Create a table for Eulerian numbers
    eulerian = [[0] * (n + 1) for _ in range(n + 1)]
    eulerian[1][0] = 1

    # Fill the table using recurrence relation
    for i in range(2, n + 1):
        for j in range(i):
            if j == 0:
                eulerian[i][j] = eulerian[i-1][j]
            else:
                eulerian[i][j] = (j + 1) * eulerian[i-1][j] + (i - j) * eulerian[i-1][j-1]

    return eulerian[n][m]

