    count = 0
    for i in range(n):
        rotated = s[i % len(s):] + s[:i % len(s)]
        if rotated[-1] == '1':
            count += 1
    return count

def odd_Equivalent(s, k):
    if not s:
        return 0

    n = len(s)
    count = 0

    # Check original string (rotation 0)
    if s[-1] == '1':
        count += 1

    # Check k rotations
    for i in range(1, k + 1):
        # Rotate left by 1 position
        rotated = s[1:] + s[:1]
        if rotated[-1] == '1':
            count += 1

    return count

