def search(arr):
    """
    Find the element that appears only once in a sorted array.
    All other elements appear exactly twice.
    """
    left = 0
    right = len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # If mid is even, compare with mid+1
        if mid % 2 == 0:
            if arr[mid] == arr[mid + 1]:
                # Unique element is to the right
                left = mid + 2
            else:
                # Unique element is at mid or to the left
                right = mid
        else:
            # If mid is odd, compare with mid-1
            if arr[mid] == arr[mid - 1]:
                # Unique element is to the left
                right = mid - 2
            else:
                # Unique element is at mid or to the right
                left = mid + 1

    return arr[left]

def search(arr):
    """
    Find the element that appears only once in a sorted array.
    Uses binary search for O(log n) time complexity.
    """
    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        if mid % 2 == 0:
            # mid is even, check if it's the first of a pair
            if mid + 1 < len(arr) and arr[mid] == arr[mid + 1]:
                # Pair found, unique element is to the right
                left = mid + 2
            else:
                # Unique element found at mid
                return arr[mid]
        else:
            # mid is odd, check if it's the second of a pair
            if mid > 0 and arr[mid] == arr[mid - 1]:
                # Pair found, unique element is to the left
                right = mid - 2
            else:
                # Unique element found at mid
                return arr[mid]

    return arr[left]

