def find_solution(a, b, n):
    """
    Find integers x and y such that ax + by = n.
    Returns (x, y) if a solution exists, None otherwise.
    """
    # Handle edge cases
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    if a == 0:
        if n % b == 0:
            return (0, n // b)
        return None

    if b == 0:
        if n % a == 0:
            return (n // a, 0)
        return None

    # Extended Euclidean Algorithm
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        else:
            gcd, x1, y1 = extended_gcd(b, a % b)
            x = y1
            y = x1 - (a // b) * y1
            return gcd, x, y

    gcd, x0, y0 = extended_gcd(a, b)

    # Check if solution exists (n must be divisible by gcd(a,b))
    if n % gcd != 0:
        return None

    # Scale the solution
    multiplier = n // gcd
    x = x0 * multiplier
    y = y0 * multiplier

    return (x, y)

