def sequence(n):
    memo = {}

    def compute(k):
        if k == 1:
            return 1
        if k in memo:
            return memo[k]
        if k == 2:
            return 2
        result = compute(compute(k-1)) + compute(k - compute(k-1))
        memo[k] = result
        return result

    return compute(n)

