def sequence(n):
    memo = {}

    def helper(k):
        if k == 1:
            return 1
        if k in memo:
            return memo[k]

        # Newman-Conway sequence: a(n) = a(a(n-1)) + a(n - a(n-1))
        result = helper(helper(k-1)) + helper(k - helper(k-1))
        memo[k] = result
        return result

    return helper(n)

