def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    result = list(s)
    vowels_list = []
    vowel_positions = []

    # Find all vowels and their positions
    for i, char in enumerate(s):
        if char in vowels:
            vowels_list.append(char)
            vowel_positions.append(i)

    # Reverse the vowels
    vowels_list.reverse()

    # Place reversed vowels back
    for i, pos in enumerate(vowel_positions):
        result[pos] = vowels_list[i]

    return ''.join(result)

def reverse_vowels(s):
    vowels = set('aeiouAEIOU')
    chars = list(s)
    vowels_indices = [i for i, c in enumerate(chars) if c in vowels]
    vowels_values = [chars[i] for i in vowels_indices]
    vowels_values_reversed = vowels_values[::-1]
    for i, v in enumerate(vowels_values_reversed):
        chars[vowels_indices[i]] = v
    return ''.join(chars)

