def find_solution(a, b, n):
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        else:
            g, x1, y1 = extended_gcd(b, a % b)
            x = y1
            y = x1 - (a // b) * y1
            return g, x, y

    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    gcd, x, y = extended_gcd(a, b)

    if n % gcd != 0:
        return None

    x *= n // gcd
    y *= n // gcd

    return (x, y)

