def find_solution(a, b, n):
    # Handle edge cases
    if a == 0 and b == 0:
        return None
    if a == 0:
        if n % b == 0:
            return (n // b, 0)
        return None
    if b == 0:
        if n % a == 0:
            return (0, n // a)
        return None

    # Extended Euclidean Algorithm
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return gcd, x, y

    gcd, x0, y0 = extended_gcd(a, b)

    # Check if solution exists
    if n % gcd != 0:
        return None

    # Scale the solution
    factor = n // gcd
    x = x0 * factor
    y = y0 * factor

    return (x, y)

